  const down = dockerPs.split('\n').filter(line => line.includes('Exited') || line.includes('Restarting'));
  let report = "";

  if (down.length > 0) {
    const results = down.map(line => {
      const name = line.split(' ')[0];
      try {
        cp.execSync(`docker restart ${name}`);
        return `✅ Reiniciado: ${name}`;
      } catch (e) {
        return `❌ Falló reinicio: ${name} (${e.message})`;
      }
    });
    report = `🚨 Problemas detectados:\n${down.join('\n')}\n\nACCIONES TOMADAS:\n${results.join('\n')}`;
  } else {
    report = "✅ Todo en orden. Todos los contenedores están Up.";
  }
  return { json: { output: report } };
} catch (e) {
  return { json: { output: "Error ejecutando el doctor: " + e.message } };
}

