const http = require('http');

const query = (items[0].json && items[0].json.query) ? items[0].json.query : '¿Qué es NiN?';
const OLLAMA_HOST = '172.24.0.1';
const OLLAMA_PORT = 11434;
const QDRANT_HOST = '172.24.0.1';
const QDRANT_PORT = 6335;

// 1. Obtener Embedding de Ollama
const getEmbedding = () => new Promise((resolve, reject) => {
  const reqPayload = JSON.stringify({ model: 'nomic-embed-text:latest', prompt: query });
  const req = http.request({ hostname: OLLAMA_HOST, port: OLLAMA_PORT, path: '/api/embeddings', method: 'POST', headers: {'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(reqPayload)} }, (res) => {
    let body = ''; res.on('data', chunk => body += chunk); res.on('end', () => {
      try { resolve(JSON.parse(body).embedding); } catch(e) { reject('Error parseando Ollama'); }
    });
  });
  req.on('error', reject); req.write(reqPayload); req.end();
});

// 2. Buscar en Qdrant
const searchQdrant = (vector) => new Promise((resolve, reject) => {
  const reqPayload = JSON.stringify({
    vector: vector, limit: 3, with_payload: true
  });
  const req = http.request({ hostname: QDRANT_HOST, port: QDRANT_PORT, path: '/collections/cerebro_lucy/points/search', method: 'POST', headers: {'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(reqPayload)} }, (res) => {
    let body = ''; res.on('data', chunk => body += chunk); res.on('end', () => {
      try { resolve(JSON.parse(body).result); } catch(e) { reject('Error parseando Qdrant'); }
    });
  });
  req.on('error', reject); req.write(reqPayload); req.end();
});

try {
  const embedding = await getEmbedding();
  const qdrantResults = await searchQdrant(embedding);

  if (!qdrantResults || qdrantResults.length === 0) return [{ json: { output: '🔍 No se encontraron fragmentos relevantes en el Cerebro NIN.' } }];

  const formatted = qdrantResults.map((r, i) => {
    const meta = r.payload && r.payload.metadata ? r.payload.metadata : {};
    const content = r.payload ? (r.payload.pageContent || '') : '';
    return `${i+1}. [${meta.source || 'Doc'}] (Score: ${r.score})\n   ${content.substring(0, 500)}...`;
  }).join('\n\n---\n\n');

  return [{ json: { output: `🔍 Resultados de búsqueda en el Cerebro NIN:\n\n${formatted}` } }];
} catch (error) {
  return [{ json: { output: `Error interno al consultar Cerebro: ${error.message || error}` } }];
}

